.top-tabs-banner {
    position: relative;
    width: auto;
    margin-left: calc(50% - 50vw);
    margin-right: calc(50% - 50vw);
    height: 35vh;
    min-height: 200px;
    border-radius: 0;
    overflow: hidden;
    box-shadow: 0 24px 60px rgba(15, 23, 42, 0.16);
}

.top-tabs-banner-image {
    width: 100%;
    height: 100%;
    min-height: 220px;
    object-fit: cover;
    display: block;
}

.top-tabs-banner-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(115deg, rgba(10, 22, 40, 0.82) 10%, rgba(10, 22, 40, 0.42) 52%, rgba(0, 180, 216, 0.18) 100%);
}
.top-tabs-content {
    position: absolute;
    inset: 0;
    z-index: 2;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    text-align: center;
    padding: 24px 20px;
}
.top-tabs-title {
    max-width: 760px;
    color: #ffffff;
    font-size: clamp(24px, 3vw, 40px);
    font-weight: 800;
    text-transform: uppercase;
    /* line-height: 1.12; */
    margin-bottom: 18px;
}
.top-tabs-actions {
    max-width: 860px;
}
.top-tab:hover::after,
.top-tab.active::after {
    transform: scaleX(1);
}
.top-tab.active {
    background: linear-gradient(135deg, rgba(0, 180, 216, 0.9), rgba(30, 58, 95, 0.92));
    border-color: rgba(255, 255, 255, 0.26);
    color: #ffffff;
}
.top-tab {
    padding: 11px 20px;
    border: 1px solid rgba(255, 255, 255, 0.22);
    background: rgba(255, 255, 255, 0.12);
    backdrop-filter: blur(10px);
    font-weight: 600;
    font-size: 0.92rem;
    cursor: pointer;
    position: relative;
    color: #ffffff;
    border-radius: 999px;
    transition: all 0.3s ease;
    box-shadow: 0 10px 24px rgba(15, 23, 42, 0.12);
}

.top-tab::after {
    content: '';
    position: absolute;
    left: 18px;
    right: 18px;
    bottom: 8px;
    height: 2px;
    transform: scaleX(0);
    transform-origin: center;
    background: linear-gradient(90deg, var(--accent), var(--gold));
    transition: transform 0.3s ease;
}

.top-tab:hover::after,
.top-tab.active::after {
    transform: scaleX(1);
}

.top-tab:hover {
    transform: translateY(-2px);
    background: rgba(255, 255, 255, 0.2);
    color: #ffffff;
}

.top-tab.active {
    background: linear-gradient(135deg, rgba(0, 180, 216, 0.9), rgba(30, 58, 95, 0.92));
    border-color: rgba(255, 255, 255, 0.26);
    color: #ffffff;
}
@media (max-width: 767.98px) {
    .top-tabs-banner {
        min-height: 260px;
    }

    .top-tabs-banner-image {
        min-height: 260px;
    }

    .top-tabs-content {
        padding: 20px 16px;
    }

    .top-tabs-title {
        font-size: 22px;
        margin-bottom: 14px;
    }

    .top-tab {
        width: 100%;
        justify-content: center;
    }
}



.tab-content-custom {
    display: none;
    animation: fadeIn 0.5s ease;
}

.tab-content-custom.active {
    display: block;
}
.course-card {
  border-radius: 15px;
  overflow: hidden;
  transition: 0.3s;
}

.course-card:hover {
  transform: translateY(-5px);
}

.card-img-top {
  height: 200px;
  object-fit: cover;
}

.accordion-button {
  font-size: 14px;
}

.accordion-button:not(.collapsed) {
  background-color: #f8f9fa;
  box-shadow: none;
}

.admission-process-section {
  background: linear-gradient(180deg, #f8fafc 0%, #eef4fb 100%);
}

.admission-process-wrap {
  background: #ffffff;
  border-radius: 20px;
  box-shadow: 0 14px 35px rgba(30, 58, 95, 0.08);
}

.admission-info-box,
.admission-step-card,
.admission-support-box {
  background: #ffffff;
  border: 1px solid rgba(30, 58, 95, 0.08);
  border-radius: 18px;
  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.05);
}

.admission-info-box {
  padding: 24px;
}

.admission-checklist {
  display: grid;
  gap: 12px;
}

.admission-checklist div {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  color: #475569;
  line-height: 1.6;
}

.admission-checklist i {
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background: rgba(0, 180, 216, 0.12);
  color: #00b4d8;
  font-size: 0.8rem;
  flex-shrink: 0;
  margin-top: 1px;
}

.admission-step-card {
  position: relative;
  padding: 24px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.admission-step-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 16px 30px rgba(30, 58, 95, 0.1);
}

.admission-step-badge {
  position: absolute;
  top: 18px;
  right: 18px;
  font-size: 0.82rem;
  font-weight: 700;
  color: #1e3a5f;
  background: rgba(240, 165, 0, 0.12);
  padding: 6px 10px;
  border-radius: 999px;
}

.admission-step-icon {
  width: 58px;
  height: 58px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 18px;
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(0, 180, 216, 0.14), rgba(30, 58, 95, 0.12));
  color: #1e3a5f;
  font-size: 1.2rem;
}

.admission-step-card h5 {
  color: #1e3a5f;
  margin-bottom: 12px;
}

.admission-support-box {
  padding: 22px 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 18px;
}

.admission-support-box h5 {
  color: #1e3a5f;
}

.admission-support-box .btn {
  white-space: nowrap;
  border-radius: 999px;
  padding: 10px 22px;
  font-weight: 600;
}

.quick-info-card {
  height: 100%;
  padding: 24px;
  background: #ffffff;
  border: 1px solid rgba(30, 58, 95, 0.08);
  border-radius: 18px;
  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.05);
}

.quick-info-card i {
  width: 54px;
  height: 54px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(0, 180, 216, 0.14), rgba(30, 58, 95, 0.12));
  color: #1e3a5f;
  font-size: 1.15rem;
}

.quick-info-card h6,
.quick-info-card h5 {
  color: #1e3a5f;
}

.apply-inline-form {
  padding: 28px;
  background: #f8fbff;
  border: 1px solid rgba(30, 58, 95, 0.08);
  border-radius: 18px;
}

.apply-inline-form .form-label {
  font-weight: 600;
  color: #1e3a5f;
}

.apply-inline-form .form-control,
.apply-inline-form .form-select {
  border-radius: 12px;
  padding: 12px 14px;
  border: 1px solid #dbe4ef;
}

.apply-inline-form .form-control:focus,
.apply-inline-form .form-select:focus {
  border-color: #00b4d8;
  box-shadow: 0 0 0 3px rgba(0, 180, 216, 0.12);
}

@media (max-width: 767.98px) {
  .admission-process-wrap {
    padding: 2rem 1.25rem !important;
  }

  .admission-support-box {
    flex-direction: column;
    align-items: flex-start;
  }

  .admission-support-box .btn {
    width: 100%;
  }

  .apply-inline-form {
    padding: 20px;
  }
}
